#include "motor_encoder.h"
#include <Arduino.h>
#define MOT_PWM 25
#define MOT_DIR 26
#define ENC_A 32
#define ENC_B 33
static volatile long _pos=0;
static float _rpm=0;static long _lastPos=0;static unsigned long _last=0;
void IRAM_ATTR _enc_isr(){int b=digitalRead(ENC_B);_pos+=(b?1:-1);}
void motor_enc_setup(){pinMode(MOT_DIR,OUTPUT);ledcAttach(MOT_PWM,5000,8);pinMode(ENC_A,INPUT_PULLUP);pinMode(ENC_B,INPUT_PULLUP);attachInterrupt(ENC_A,_enc_isr,RISING);Serial.println("[motor_enc] OK");}
void motor_enc_set_speed(int s){digitalWrite(MOT_DIR,s>=0?HIGH:LOW);ledcWrite(MOT_PWM,constrain(abs(s),0,255));}
long motor_enc_get_position(){return _pos;}
void motor_enc_reset_position(){_pos=0;}
float motor_enc_get_rpm(){if(millis()-_last>=100){long dp=_pos-_lastPos;_rpm=dp*600.0/334.0;_lastPos=_pos;_last=millis();}return _rpm;}
